const input = $input.first().json;
const body = input.body || input;
const topic_id = body.topic_id;
const project_id = body.project_id;

// Auth check
const authHeader = input.headers?.authorization || '';
const expected = 'Bearer ' + $env.DASHBOARD_API_TOKEN;
if (authHeader !== expected) {
  throw new Error('Unauthorized');
}

if (!topic_id) throw new Error('topic_id is required');

return [{ json: { topic_id, project_id } }];

const assembled = $('Assemble Script').first().json;
const combined_text = assembled.combined_text;
const topic = assembled.topic;
const project = assembled.project;

// === MECHANICAL SPLIT: Split text at sentence boundaries into ~110-word chunks ===
// Claude NEVER sees narration text. 100% preservation guaranteed.

function splitIntoSentences(text) {
  const cleaned = text.replace(/^#+\s*/gm, '').replace(/\[.*?\]/g, '').replace(/\*\*/g, '').trim();
  const raw = cleaned.split(/(?<=[.!?])\s+(?=[A-Z"\u201C])|\n\n+/);
  return raw.map(s => s.trim()).filter(s => s.length > 0);
}

function groupIntoChunks(sentences, targetWords) {
  const chunks = [];
  let current = [];
  let currentWords = 0;
  for (const sentence of sentences) {
    const words = sentence.split(/\s+/).length;
    if (currentWords > 0 && currentWords + words > targetWords + 20) {
      chunks.push(current.join(' '));
      current = [sentence];
      currentWords = words;
    } else {
      current.push(sentence);
      currentWords += words;
    }
  }
  if (current.length > 0) chunks.push(current.join(' '));
  return chunks;
}

const sentences = splitIntoSentences(combined_text);
const chunks = groupIntoChunks(sentences, 110);

const originalWords = combined_text.replace(/^#+\s*/gm, '').replace(/\[.*?\]/g, '').replace(/\*\*/g, '').trim().split(/\s+/).length;
const chunkWords = chunks.reduce((sum, c) => sum + c.split(/\s+/).length, 0);

console.log('Mechanical split: ' + chunks.length + ' chunks, ' + chunkWords + ' words (original: ' + originalWords + ')');

// Build metadata-only prompt for Claude — send FULL narration for context
const chunkList = chunks.map((c, i) => 'CHUNK ' + (i+1) + ': ' + c).join('\n\n');

const metadataPrompt = 'Below are ' + chunks.length + ' text chunks from a documentary script about "' + (topic.seo_title || topic.original_title) + '".\n\nFor EACH chunk, generate ONLY:\n1. image_prompt: 40-80 words, cinematic. Structure: [SUBJECT] + [ENVIRONMENT] + [LIGHTING] + [COMPOSITION] + [MOOD] + [DETAILS]. Be hyper-specific. People as silhouettes/hands/figures from behind. Include lighting direction. No text/words/signs in images.\n2. emotional_beat: one of hook, tension, revelation, data, story, resolution, transition\n3. chapter: a short chapter name grouping related scenes\n\nReturn ONLY a JSON array: [{"scene_number": 1, "image_prompt": "...", "emotional_beat": "...", "chapter": "..."}]\n\nDo NOT return or modify any narration text. I only need image_prompt, emotional_beat, and chapter for each chunk number.\n\n' + chunkList;

return [{ json: {
  chunks,
  chunk_count: chunks.length,
  original_words: originalWords,
  chunk_words: chunkWords,
  metadata_prompt: metadataPrompt,
  topic_id: topic.id,
  project_id: project.id,
  combined_score: assembled.combined_score,
  force_passed: assembled.force_passed,
  attempt: assembled.attempt
} }];

const visualResponse = $input.first().json;
const buildData = $('Build Visual Prompt').first().json;
const topic_id = buildData.topic_id;
const project_id = buildData.project_id;
const chunks = buildData.chunks;
const originalWords = buildData.original_words;

if (visualResponse.error) {
  throw new Error('Visual Assignment failed: ' + (visualResponse.error.message || JSON.stringify(visualResponse.error)));
}

// Parse Claude's metadata-only response
let metadata = [];
try {
  const text = (visualResponse.content || []).filter(c => c.type === 'text').map(c => c.text).join('');
  const cleaned = text.replace(/^```(?:json)?\s*/m, '').replace(/\s*```$/m, '').trim();
  const s = cleaned.indexOf('[');
  const e = cleaned.lastIndexOf(']');
  if (s >= 0 && e > s) metadata = JSON.parse(cleaned.substring(s, e + 1));
} catch(err) {
  console.warn('Metadata parse failed, using defaults');
}

// Merge: mechanical narration chunks (100% preserved) + Claude metadata
const scenes_array = chunks.map((narration, i) => {
  const meta = metadata.find(m => m.scene_number === i + 1) || metadata[i] || {};
  return {
    topic_id,
    project_id,
    scene_number: i + 1,
    scene_id: 'scene_' + String(i + 1).padStart(3, '0'),
    narration_text: narration,
    image_prompt: meta.image_prompt || 'Documentary scene, cinematic lighting, moody atmosphere',
    visual_type: 'static_image',
    emotional_beat: meta.emotional_beat || 'story',
    chapter: meta.chapter || '',
    audio_status: 'pending',
    image_status: 'pending',
    clip_status: 'pending',
    skipped: false
  };
});

const word_count = scenes_array.reduce((sum, s) => sum + s.narration_text.split(/\s+/).length, 0);
const scene_count = scenes_array.length;

// Verify 100% preservation
const preservationRatio = word_count / originalWords;
console.log('Word count: ' + word_count + ' / ' + originalWords + ' = ' + (preservationRatio * 100).toFixed(1) + '% preserved');
if (preservationRatio < 0.95) {
  throw new Error('PRESERVATION FAILED: ' + word_count + ' / ' + originalWords + ' words (' + (preservationRatio * 100).toFixed(1) + '%). Mechanical split should be ~100%.');
}

const script_json = JSON.stringify(scenes_array);
const script_metadata = JSON.stringify({
  video_metadata: {
    title: $('Assemble Script').first().json.topic.seo_title || $('Assemble Script').first().json.topic.original_title,
    description: 'A detailed documentary about ' + ($('Assemble Script').first().json.topic.narrative_hook || ''),
    tags: ['documentary', $('Assemble Script').first().json.project.niche || ''],
    thumbnail_prompt: scenes_array[0]?.image_prompt || ''
  },
  generation_stats: { word_count, scene_count, quality_score: buildData.combined_score, force_passed: buildData.force_passed, attempt: buildData.attempt, original_words: originalWords, preservation_ratio: preservationRatio, method: 'mechanical_split_v1' }
});

return [{ json: { scenes_array, script_json, script_metadata, word_count, scene_count, topic_id, project_id, combined_score: buildData.combined_score, force_passed: buildData.force_passed, attempt: buildData.attempt } }];

const errData = $input.first().json;
const topic_id = errData.topic_id || $('Validate Request').first().json?.topic_id;
const project_id = errData.project_id || $('Validate Request').first().json?.project_id;
const error_message = errData.error_message || errData.message || 'Unknown error in script generation';
return [{ json: { topic_id, project_id, error_message } }];

const SB = $env.SUPABASE_URL, SRK = $env.SUPABASE_SERVICE_ROLE_KEY;
const topicRaw = $('Read Topic').first().json;
const projRaw = $('Read Project').first().json;
const topic = Array.isArray(topicRaw) ? topicRaw[0] : topicRaw;
const project = Array.isArray(projRaw) ? projRaw[0] : projRaw;
const hdr = {'apikey': SRK, 'Authorization': 'Bearer ' + SRK};

var avResp = await fetch(SB + '/rest/v1/avatars?topic_id=eq.' + topic.id + '&select=*&limit=1', {headers: hdr});
var avatars = await avResp.json();
var avatar = (avatars && avatars[0]) || {};

var researchBrief = '';
try {
  var npResp = await fetch(SB + '/rest/v1/niche_profiles?project_id=eq.' + project.id + '&select=blue_ocean_opportunities,audience_pain_points,competitor_analysis&limit=1', {headers: hdr});
  var np = (await npResp.json())[0] || null;
  var yaResp = await fetch(SB + '/rest/v1/yt_video_analyses?project_id=eq.' + project.id + '&select=ten_x_strategy,blue_ocean_analysis,comment_insights,verdict&limit=10', {headers: hdr});
  var analyses = await yaResp.json();
  var rcResp = await fetch(SB + '/rest/v1/research_categories?project_id=eq.' + project.id + '&select=category_name,video_title_suggestion,ranking_score&order=ranking_score.desc&limit=10', {headers: hdr});
  var categories = await rcResp.json();
  var sections = [];
  if (np) {
    if (np.blue_ocean_opportunities) { sections.push('BLUE OCEAN OPPORTUNITIES:\n' + (typeof np.blue_ocean_opportunities === 'string' ? np.blue_ocean_opportunities : JSON.stringify(np.blue_ocean_opportunities)).substring(0,1500)); }
    if (np.audience_pain_points) { sections.push('AUDIENCE PAIN POINTS:\n' + (typeof np.audience_pain_points === 'string' ? np.audience_pain_points : JSON.stringify(np.audience_pain_points)).substring(0,1500)); }
    if (np.competitor_analysis) { sections.push('COMPETITOR GAPS:\n' + (typeof np.competitor_analysis === 'string' ? np.competitor_analysis : JSON.stringify(np.competitor_analysis)).substring(0,1000)); }
  }
  if (analyses && analyses.length > 0) {
    var strategies = analyses.filter(function(a){return a.ten_x_strategy;}).map(function(a){var s=a.ten_x_strategy; return '- '+(s.recommended_angle||s.description||JSON.stringify(s).substring(0,200));}).join('\n');
    if (strategies) sections.push('10x STRATEGIES:\n' + strategies.substring(0,1500));
    var comments = analyses.filter(function(a){return a.comment_insights;}).map(function(a){var ci=a.comment_insights; var d=ci.audience_demands||ci.top_demands||ci.key_themes||[]; return Array.isArray(d)?d.join(', '):String(d).substring(0,300);}).filter(function(c){return c;}).join('; ');
    if (comments) sections.push('AUDIENCE DEMANDS:\n' + comments.substring(0,1000));
    var boA = analyses.filter(function(a){return a.blue_ocean_analysis;}).map(function(a){var b=a.blue_ocean_analysis; return (b.gaps_and_opportunities||b.untapped||JSON.stringify(b)).substring(0,300);}).join('; ');
    if (boA) sections.push('BLUE OCEAN GAPS FROM VIDEO ANALYSIS:\n' + boA.substring(0,1000));
  }
  if (categories && categories.length > 0) {
    var cats = categories.slice(0,5).map(function(c){return '- '+(c.category_name||'')+': '+(c.video_title_suggestion||'');}).join('\n');
    sections.push('TOP RESEARCH CATEGORIES:\n' + cats);
  }
  try {
    var aiResp = await fetch(SB + '/rest/v1/audience_insights?project_id=eq.' + project.id + '&select=audience_context_block&order=week_of.desc&limit=1', {headers: hdr});
    var aiRows = await aiResp.json();
    if (aiRows && aiRows[0] && aiRows[0].audience_context_block) { sections.push('AUDIENCE CONTEXT:\n' + aiRows[0].audience_context_block); }
  } catch (e2) {}
  if (sections.length > 0) {
    researchBrief = '=== RESEARCH BRIEF ===\n\n' + sections.join('\n\n') + '\n\n=== END RESEARCH BRIEF ===';
  }
} catch (e) {}

var ctx = project.channel_analysis_context || {};
var scriptTargets = project.script_depth_targets;
var topicsToAvoid = project.topics_to_avoid || [];
var recAngle = project.recommended_angle || '';

var intelligence_block = '';
if (Object.keys(ctx).length > 0 || topicsToAvoid.length > 0 || recAngle) {
  intelligence_block += '\n\n=== COMPETITIVE INTELLIGENCE FOR SCRIPTING ===\n';
  if (recAngle) { intelligence_block += '\nCHANNEL POSITIONING: ' + recAngle + '\nWrite from this angle.\n'; }
  if (scriptTargets) { intelligence_block += '\nSCRIPT DEPTH TARGETS: ' + JSON.stringify(scriptTargets) + '\nOur 3-pass system should EXCEED these.\n'; }
  if (ctx.comment_pain_points && ctx.comment_pain_points.length > 0) { intelligence_block += '\nAUDIENCE PAIN POINTS TO ADDRESS:\n'; ctx.comment_pain_points.forEach(function(p) { intelligence_block += '- ' + p + '\n'; }); }
  if (ctx.comment_content_gaps && ctx.comment_content_gaps.length > 0) { intelligence_block += '\nCONTENT GAPS TO FILL:\n'; ctx.comment_content_gaps.forEach(function(g) { intelligence_block += '- ' + g + '\n'; }); }
  if (ctx.comment_top_questions && ctx.comment_top_questions.length > 0) { intelligence_block += '\nTOP VIEWER QUESTIONS TO ANSWER:\n'; ctx.comment_top_questions.forEach(function(q) { intelligence_block += '- ' + q + '\n'; }); }
  if (topicsToAvoid.length > 0) { intelligence_block += '\nANGLES TO AVOID (saturated):\n'; topicsToAvoid.forEach(function(t) { intelligence_block += '- ' + t + '\n'; }); }
  if (ctx.differentiation_strategy) { intelligence_block += '\nDIFFERENTIATION: ' + (typeof ctx.differentiation_strategy === 'string' ? ctx.differentiation_strategy : JSON.stringify(ctx.differentiation_strategy)) + '\n'; }
}

var scriptRef = project.script_reference_data;
if (scriptRef) { intelligence_block += '\nCOMPETITOR SCRIPTING STYLES:\n' + JSON.stringify(scriptRef) + '\n'; }
var revProj = project.revenue_projections;
if (revProj) { intelligence_block += '\nREVENUE CONTEXT: ' + JSON.stringify(revProj) + '\n'; }
var viabScore = project.niche_viability_score;
var viabVerdict = project.niche_viability_verdict;
if (viabScore || viabVerdict) { intelligence_block += '\nVIABILITY: ' + (viabScore || 'N/A') + '/100 - ' + (viabVerdict || 'N/A') + '\n'; }
var titleDna = project.title_dna_patterns;
if (titleDna) { intelligence_block += '\nTITLE DNA: ' + JSON.stringify(titleDna) + '\n'; }
var thumbDna = project.thumbnail_dna_patterns;
if (thumbDna) { intelligence_block += '\nTHUMBNAIL DNA: ' + JSON.stringify(thumbDna) + '\n'; }
if (ctx.blue_ocean_gaps && ctx.blue_ocean_gaps.length > 0) { intelligence_block += '\nBLUE-OCEAN GAPS:\n'; ctx.blue_ocean_gaps.forEach(function(g) { var l = typeof g === 'string' ? g : (g.topic || g.opportunity || JSON.stringify(g)); intelligence_block += '- ' + l + '\n'; }); }
if (ctx.content_pillars && ctx.content_pillars.length > 0) { intelligence_block += '\nPILLARS: ' + ctx.content_pillars.join(', ') + '\n'; }
if (ctx.moat_indicators) { intelligence_block += '\nMOAT: ' + JSON.stringify(ctx.moat_indicators) + '\n'; }
if (ctx.comment_requested_topics && ctx.comment_requested_topics.length > 0) { intelligence_block += '\nVIEWER REQUESTS:\n'; ctx.comment_requested_topics.forEach(function(t) { intelligence_block += '- ' + t + '\n'; }); }

return [{json: {topic: topic, project: project, avatar: avatar, pass_number: 1, research_brief: researchBrief, intelligence_block: intelligence_block}}];

const pass1 = $input.first().json;
const prep = $('Prep & Read Avatar').first().json;
const {topic, project, avatar, research_brief} = prep;
const SB = $env.SUPABASE_URL, SRK = $env.SUPABASE_SERVICE_ROLE_KEY;

const passScores = {pass_1: {attempts: pass1.attempt, final_score: pass1.composite_score, verdict: pass1.verdict, scores: pass1.scores}};
await fetch(SB + '/rest/v1/topics?id=eq.' + topic.id, {
  method: 'PATCH',
  headers: {'apikey': SRK, 'Authorization': 'Bearer ' + SRK, 'Content-Type': 'application/json', 'Prefer': 'return=minimal'},
  body: JSON.stringify({script_pass_scores: passScores})
});

return [{json: {topic, project, avatar, pass_number: 2, pass1_output: pass1.pass_text, pass1_scores: passScores, research_brief: research_brief || ''}}];

const pass2 = $input.first().json;
const handleP1 = $('Handle Pass 1 + Prep Pass 2').first().json;
const {topic, project, avatar, pass1_output, pass1_scores, research_brief} = handleP1;
const SB = $env.SUPABASE_URL, SRK = $env.SUPABASE_SERVICE_ROLE_KEY, AK = $env.ANTHROPIC_API_KEY;

const passScores = {...pass1_scores, pass_2: {attempts: pass2.attempt, final_score: pass2.composite_score, verdict: pass2.verdict, scores: pass2.scores}};
await fetch(SB + '/rest/v1/topics?id=eq.' + topic.id, {
  method: 'PATCH',
  headers: {'apikey': SRK, 'Authorization': 'Bearer ' + SRK, 'Content-Type': 'application/json', 'Prefer': 'return=minimal'},
  body: JSON.stringify({script_pass_scores: passScores})
});

const pResp = await fetch(SB + '/rest/v1/system_prompts?prompt_type=eq.script_metadata_extractor&is_active=eq.true&select=prompt_text', {
  headers: {'apikey': SRK, 'Authorization': 'Bearer ' + SRK}
});
const extractPromptRaw = ((await pResp.json())?.[0]?.prompt_text) || '';
const extractPrompt = extractPromptRaw || 'Read the following script pass and extract:\n1. A 200-word summary of the content covered, argument structure, and emotional arc\n2. The primary case study character name and a 1-sentence description of where they are in their arc\n3. A list of ALL metaphors and analogies used\n4. A list of ALL reassurance phrases used\n5. A list of any other distinctive phrases that should not be repeated\n\nRESPOND IN JSON:\n{"summary": "", "character_name": "", "character_status": "", "metaphors_used": [], "reassurance_phrases_used": [], "notable_phrases": []}';

async function extract(text) {
  const prompt = extractPrompt + '\n\nSCRIPT:\n---\n' + text.substring(0, 60000) + '\n---';
  const r = await fetch('https://api.anthropic.com/v1/messages', {
    method: 'POST',
    headers: {'Content-Type': 'application/json', 'x-api-key': AK, 'anthropic-version': '2023-06-01'},
    body: JSON.stringify({model: 'claude-sonnet-4-20250514', max_tokens: 4096, messages: [{role: 'user', content: prompt}]})
  });
  const d = await r.json();
  const txt = (d.content || []).filter(c => c.type === 'text').map(c => c.text).join('');
  try {
    const c = txt.replace(/^```(?:json)?\s*/m, '').replace(/\s*```$/m, '').trim();
    return JSON.parse(c.substring(c.indexOf('{'), c.lastIndexOf('}') + 1));
  } catch (e) {
    return {summary: txt.substring(0, 400), character_name: '', character_status: '', metaphors_used: [], reassurance_phrases_used: [], notable_phrases: []};
  }
}

const [p1Meta, p2Meta] = await Promise.all([extract(pass1_output), extract(pass2.pass_text)]);

return [{json: {
  topic, project, avatar, pass_number: 3,
  pass1_summary: p1Meta.summary || '',
  pass2_summary: p2Meta.summary || '',
  character_name: p1Meta.character_name || '',
  character_status: p2Meta.character_status || p1Meta.character_status || '',
  metaphors_used: [...(p1Meta.metaphors_used || []), ...(p2Meta.metaphors_used || [])],
  reassurance_phrases: [...(p1Meta.reassurance_phrases_used || []), ...(p2Meta.reassurance_phrases_used || [])],
  notable_phrases: [...(p1Meta.notable_phrases || []), ...(p2Meta.notable_phrases || [])],
  pass1_text: pass1_output, pass2_text: pass2.pass_text, passScores,
  research_brief: research_brief || ''
}}];

const pass3 = $input.first().json;
const metaPrep = $('Extract Metadata + Prep Pass 3').first().json;
const {topic, project, pass1_text, pass2_text, passScores} = metaPrep;
const SB = $env.SUPABASE_URL, SRK = $env.SUPABASE_SERVICE_ROLE_KEY;

const combined_text = pass1_text + '\n\n' + pass2_text + '\n\n' + pass3.pass_text;
const word_count = combined_text.split(/\s+/).length;

const allScores = {...passScores, pass_3: {attempts: pass3.attempt, final_score: pass3.composite_score, verdict: pass3.verdict, scores: pass3.scores}};
const avgScore = ((allScores.pass_1?.final_score || 0) + (allScores.pass_2?.final_score || 0) + (allScores.pass_3?.final_score || 0)) / 3;

const scriptMeta = {
  video_title: topic.seo_title || topic.original_title,
  niche_category: project.niche,
  total_word_count: word_count,
  estimated_duration_minutes: Math.round(word_count / 200),
  pass_scores: allScores,
  total_api_calls: ((allScores.pass_1?.attempts || 1) + (allScores.pass_2?.attempts || 1) + (allScores.pass_3?.attempts || 1)) * 2 + 2,
  manual_review_flag: [allScores.pass_1, allScores.pass_2, allScores.pass_3].some(p => p?.verdict === 'FORCE_PASS' && (p?.final_score || 0) < 5),
  metaphors_used: metaPrep.metaphors_used || [],
  case_study_character: metaPrep.character_name || ''
};

await fetch(SB + '/rest/v1/topics?id=eq.' + topic.id, {
  method: 'PATCH',
  headers: {'apikey': SRK, 'Authorization': 'Bearer ' + SRK, 'Content-Type': 'application/json', 'Prefer': 'return=minimal'},
  body: JSON.stringify({
    script_json: {combined_text, pass_1: pass1_text, pass_2: pass2_text, pass_3: pass3.pass_text},
    script_quality_score: Math.round(avgScore * 10) / 10,
    script_evaluation: scriptMeta,
    script_pass_scores: allScores,
    script_metadata_extended: scriptMeta,
    word_count,
    scene_count: null
  })
});

return [{json: {combined_text, topic, project, word_count, script_metadata: scriptMeta}}];

const items = $input.all();
const project_id = items[0].json.project_id || items[0].json.project?.id;
const SUPABASE_URL = $env.SUPABASE_URL || 'https://supabase.operscale.cloud';
const SUPABASE_KEY = $env.SUPABASE_SERVICE_ROLE_KEY;
let audience_context = '';
try {
  const resp = await fetch(
    `${SUPABASE_URL}/rest/v1/audience_insights?project_id=eq.${project_id}&order=week_of.desc&limit=1&select=audience_context_block`,
    { headers: { 'apikey': SUPABASE_KEY, 'Authorization': `Bearer ${SUPABASE_KEY}` } }
  );
  const rows = await resp.json();
  if (rows?.[0]?.audience_context_block) {
    audience_context = rows[0].audience_context_block;
  }
} catch (e) {}
return items.map(item => ({ json: { ...item.json, audience_context } }));
